const loadApprovals = async () => {
  if (!address || !revokeChain) return

  setIsLoadingApprovals(true)
  setDebugInfo('Fetching approvals...')

  try {
    console.log('🔍 Loading approvals for chain:', revokeChain.displayName, 'address:', address)
    console.log('Chain ID:', revokeChain.id)

    // Method 1: Try Zerion API (used by many wallet apps, has CORS enabled)
    console.log('Trying Zerion API...')
    setDebugInfo('Fetching from Zerion API...')

    try {
      const zerionUrl = `https://api.zerion.io/v1/wallets/${address}/positions/?filter[positions]=only_simple&currency=usd&filter[chain_ids]=${getZerionChainId(revokeChain.id)}&sort=value`
      console.log('Zerion URL:', zerionUrl)

      const zerionResponse = await fetch(zerionUrl, {
        headers: {
          'Authorization': 'Basic ' + btoa('vie_app:'),
          'Accept': 'application/json',
        },
      })

      if (zerionResponse.ok) {
        const zerionData = await zerionResponse.json()
        console.log('Zerion response:', zerionData)

        // Process Zerion data and check for approvals
        if (zerionData?.data) {
          console.log('Got Zerion data, now checking approvals...')
          await loadApprovalsOnChain() // Still need to check approvals on-chain
          return
        }
      }
    } catch (zerionError) {
      console.warn('Zerion API failed:', zerionError)
    }

    // Method 2: Direct on-chain check (fastest and most reliable)
    console.log('Using direct on-chain approval check...')
    setDebugInfo('Checking approvals on-chain...')
    await loadApprovalsOnChain()

  } catch (error) {
    const err = error as Error
    console.error('❌ Failed to load approvals:', err)
    toast.error(`Failed to load approvals: ${err.message}`)
  } finally {
    setIsLoadingApprovals(false)
  }
}

const getZerionChainId = (chainId: number): string => {
  const chainMap: Record<number, string> = {
    1: 'ethereum',
    8453: 'base',
    42161: 'arbitrum',
    137: 'polygon',
    10: 'optimism',
    56: 'binance-smart-chain',
    43114: 'avalanche',
  }
  return chainMap[chainId] || 'ethereum'
}

